sql:
SELECT companies.company_name, companies.symbol, esg_ratings.overall_rating
FROM companies
INNER JOIN esg_ratings ON companies.company_id = esg_ratings.company_id;

external_knowledge:
- 'born in the 21st century' refers to companies founded after the year 2000;
- 'recent stellar ratings' refers to I/B/E/S estimates with a date later than January 1, 2022;
- 'consistently shone bright' refers to average summary scores greater than 80;
- 'average sparkle' refers to the average summary score;
- 'average wealth estimates' refers to average I/B/E/S estimates greater than $1,000,000.

sql:
SELECT AVG(score_change) as average_score_change
FROM equity_scores
WHERE source != 'XYZ';

SELECT overall_rating
FROM esg_ratings
WHERE source = 'MSCI' AND sector_comparison = 'Above Average';

SELECT company_id
FROM equity_scores
WHERE summary_score IN ('Bullish', 'Very Bullish');

SELECT sector, AVG(market_cap) AS average_market_cap
FROM companies
GROUP BY sector;
